function bandInterpret(score: number, bands: any[]): { cat: string; text?: string } {
  for (let i = 0; i < bands.length; i++) {
    if (score <= bands[i].max) return bands[i];
  }
  return bands[bands.length - 1];
}

// Direct port of the PSQI's real 7-component clinical scoring (subjective quality, latency,
// duration, efficiency, disturbances, medication use, daytime dysfunction) -- the one test with
// genuinely custom scoring logic rather than the standard dimension-sum-and-band approach.
function scorePsqi(rawAnswers: any[]) {
  const bedTime = rawAnswers[0], latMin = parseFloat(rawAnswers[1]) || 0, wakeTime = rawAnswers[2], hrs = parseFloat(rawAnswers[3]) || 0;
  const q5a = parseInt(rawAnswers[4]) || 0;
  const C1 = parseInt(rawAnswers[14]) || 0;
  const latScore = latMin <= 15 ? 0 : latMin <= 30 ? 1 : latMin <= 60 ? 2 : 3;
  const latSum = latScore + q5a;
  const C2 = latSum === 0 ? 0 : latSum <= 2 ? 1 : latSum <= 4 ? 2 : 3;
  const C3 = hrs > 7 ? 0 : hrs >= 6 ? 1 : hrs >= 5 ? 2 : 3;
  let C4 = 0;
  try {
    const bed = String(bedTime || "").split(":"), wake = String(wakeTime || "").split(":");
    if (bed.length === 2 && wake.length === 2 && bed[0] !== "") {
      const bedM = parseInt(bed[0]) * 60 + parseInt(bed[1]), wakeM = parseInt(wake[0]) * 60 + parseInt(wake[1]);
      let inBed = wakeM - bedM;
      if (inBed <= 0) inBed += 1440;
      if (inBed > 0 && hrs > 0) {
        const eff = (hrs * 60 / inBed) * 100;
        C4 = eff > 85 ? 0 : eff >= 75 ? 1 : eff >= 65 ? 2 : 3;
      }
    }
  } catch (_ex) { /* matches the app's own silent catch here */ }
  let distSum = 0;
  for (let i = 5; i <= 13; i++) distSum += parseInt(rawAnswers[i]) || 0;
  const C5 = distSum === 0 ? 0 : distSum <= 9 ? 1 : distSum <= 18 ? 2 : 3;
  const C6 = parseInt(rawAnswers[15]) || 0;
  const daySum = (parseInt(rawAnswers[16]) || 0) + (parseInt(rawAnswers[17]) || 0);
  const C7 = daySum === 0 ? 0 : daySum <= 2 ? 1 : daySum <= 4 ? 2 : 3;
  const global = C1 + C2 + C3 + C4 + C5 + C6 + C7;
  let lv: string;
  if (global <= 5) lv = "Good Sleep Quality";
  else if (global <= 10) lv = "Mild Sleep Difficulty";
  else if (global <= 15) lv = "Moderate Sleep Difficulty";
  else lv = "Severe Sleep Difficulty";
  return { global, lv, elevated: global > 5, max: 21 };
}

// Standard scoring path used by every test except PSQI (custom) and Big Five (percentage-based
// personality levels) -- direct port of the app's own per-dimension reverse-scoring sum plus
// band lookup.
function scoreStandardTest(t: any, testAnswers: any[]) {
  const lines: string[] = [];
  let anyElevated = false;
  let offset = 0;
  for (const dim of t.dimensions) {
    let rawSum = 0;
    for (let iIdx = 0; iIdx < dim.items.length; iIdx++) {
      const val = Number(testAnswers[offset + iIdx]) || 0;
      rawSum += dim.items[iIdx].reverse ? (dim.maxPerItem - val) : val;
    }
    offset += dim.items.length;
    if (dim.isAverage) rawSum = Math.round(rawSum / dim.items.length);

    if (dim.bands) {
      const band = bandInterpret(rawSum, dim.bands);
      const lowCats = ["Normal", "Minimal", "Low", "Lower", "Good", "Typical"];
      const isLow = lowCats.some((lc) => band.cat.indexOf(lc) !== -1);
      if (!isLow) anyElevated = true;
      const dimMax = dim.items.length * dim.maxPerItem;
      const label = dim.name ? `${dim.name}: ` : "";
      lines.push(`${label}${rawSum}/${dimMax} — ${band.cat}`);
    }
  }
  return { lines, anyElevated };
}

// Big Five personality: percentage-based Low/Moderate/High per trait, not a clinical
// elevated/not-elevated distinction -- direct port of the app's own isPersonality branch.
function scoreBigFive(t: any, testAnswers: any[]) {
  const lines: string[] = [];
  let offset = 0;
  for (const dim of t.dimensions) {
    let rawSum = 0;
    for (let iIdx = 0; iIdx < dim.items.length; iIdx++) {
      const val = Number(testAnswers[offset + iIdx]) || 0;
      rawSum += dim.items[iIdx].reverse ? (dim.maxPerItem - val) : val;
    }
    offset += dim.items.length;
    const maxPossible = dim.items.length * dim.maxPerItem;
    const pct = rawSum / maxPossible;
    const level = pct < 0.4 ? "Low" : pct < 0.65 ? "Moderate" : "High";
    lines.push(`${dim.name}: ${level} (${Math.round(pct * 100)}%)`);
  }
  return lines;
}

